import{_ as a,o as i,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"3F. Worker Wellbeing Officer","description":"","frontmatter":{"title":"3F. Worker Wellbeing Officer","eba":"Health Allied & Managers Admin 2021-2025","topics":["schedules","classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/schedules/3f-worker-wellbeing-officer.md","filePath":"ebas/has-managers-admin/schedules/3f-worker-wellbeing-officer.md"}'),t={name:"ebas/has-managers-admin/schedules/3f-worker-wellbeing-officer.md"};function l(o,e,s,c,p,h){return i(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_3f-worker-wellbeing-officer" tabindex="-1">3F. Worker Wellbeing Officer <a class="header-anchor" href="#_3f-worker-wellbeing-officer" aria-label="Permalink to &quot;3F. Worker Wellbeing Officer&quot;">​</a></h1><p>Formatting note</p><p>The schedule body below is rendered in a monospaced block to preserve the column layout of pay tables and classification grids. The block is excluded from the search index so search results stay short; find schedules by their title, number, topic or synonyms.</p><p>```text 1. The Role 1.1 A Worker Wellbeing Officer will utilise the strategic framework prescribed in the DH strategy paper “Our pathway to change: eliminating bullying and harassment in healthcare” in the promotion of the following focus areas of: (a) preventing workplace bullying and harassment (b) supporting mental health and wellbeing (c) preventing workplace injuries.</p><ol><li><p>Duties Duties include:</p><p>2.1 Development and/or maintenance of the local Worker Wellbeing Plan which aims to increase promote and support staff wellbeing across all areas of the organisation in alignment with the DH strategy paper “Our pathway to change: eliminating bullying and harassment in healthcare”</p><p>2.2 Promote the focus areas of preventing workplace bullying and harassment, supporting mental health and wellbeing and preventing workplace injuries.</p><p>2.3 Networking with the Safe Care Victoria and the Healthcare Worker Wellbeing Centre.</p></li><li><p>Qualifications/Experience Required qualifications and experience for this role is as follows:</p><p>3.1 Relevant tertiary qualifications in Human Resources, Psychology (or equivalent) or</p><p>3.2 Extensive experience in human resources, health promotion, psychology, mental health, or workplace health and wellbeing.</p><p>3.3 Knowledge of best practice in critical incident, psychological first aid and other wellbeing areas. ```</p></li></ol>',5)])])}const g=a(t,[["render",l]]);export{d as __pageData,g as default};
